PROGRAM TankLevelMonitor
VAR
    RawLevel : INT;
    HighAlarmSP : REAL := 85.0;
    LowAlarmSP : REAL := 15.0;
    Hysteresis : REAL := 2.0;
    LevelPct : REAL;
    HighAlarm : BOOL;
    LowAlarm : BOOL;
    HighOffThreshold : REAL;
    LowOnThreshold : REAL;
END_VAR

(* Преобразование сырого значения в проценты *)
LevelPct := INT_TO_REAL(RawLevel) / 276.48;

(* Вычисление порогов с гистерезисом *)
HighOffThreshold := HighAlarmSP - Hysteresis;
LowOnThreshold := LowAlarmSP + Hysteresis;

(* HighAlarm с гистерезисом:
   Включается при LevelPct >= HighAlarmSP
   Выключается при LevelPct < HighOffThreshold
   В диапазоне гистерезиса состояние не меняется *)
IF LevelPct >= HighAlarmSP THEN
    HighAlarm := TRUE;
ELSIF LevelPct < HighOffThreshold THEN
    HighAlarm := FALSE;
END_IF;

(* LowAlarm с гистерезисом:
   Включается при LevelPct <= LowAlarmSP
   Выключается при LevelPct > LowOnThreshold
   В диапазоне гистерезиса состояние не меняется *)
IF LevelPct <= LowAlarmSP THEN
    LowAlarm := TRUE;
ELSIF LevelPct > LowOnThreshold THEN
    LowAlarm := FALSE;
END_IF;

END_PROGRAM

PROGRAM MotorStarDelta
VAR_INPUT
    START_BTN : BOOL;
    STOP_BTN : BOOL;
    OVERLOAD : BOOL;
END_VAR
VAR_OUTPUT
    MAIN_CONTACTOR : BOOL;
    STAR_CONTACTOR : BOOL;
    DELTA_CONTACTOR : BOOL;
    FAULT : BOOL;
END_VAR
VAR
    startEdge : BOOL;
    motorRunning : BOOL;
    startEdgeDet : R_TRIG;
    timerStarDelta : TON;
END_VAR

(* Детектор фронта кнопки Пуск *)
startEdgeDet(CLK := START_BTN);
startEdge := startEdgeDet.Q;

(* Ланцуг удержания двигателя: пуск по фронту, стоп по кнопке или перегрузке *)
motorRunning := (motorRunning OR startEdge) AND NOT STOP_BTN AND NOT OVERLOAD;

(* Главный контактор включен при работе двигателя *)
MAIN_CONTACTOR := motorRunning;

(* Звезда включена при работе, но выключается по таймеру *)
STAR_CONTACTOR := motorRunning AND NOT timerStarDelta.Q;

(* Треугольник включается только после срабатывания таймера *)
DELTA_CONTACTOR := motorRunning AND timerStarDelta.Q;

(* Таймер запускается, когда двигатель работает и еще не истекло время *)
timerStarDelta.IN := motorRunning AND NOT timerStarDelta.Q;
timerStarDelta.PT := T#3s;

(* Выход аварии отражает состояние перегрузки *)
FAULT := OVERLOAD;
END_PROGRAM

FUNCTION_BLOCK PID_Temperature
VAR_INPUT
    Enable : BOOL;
    Setpoint : REAL;
    ProcessValue : REAL;
    Kp : REAL := 2.0;
    Ki : REAL := 0.05;
    Kd : REAL := 0.0;
    CycleTime : TIME := T#100ms;
END_VAR
VAR_OUTPUT
    Output : REAL;
END_VAR
VAR
    Integral : REAL := 0.0;
    PrevError : REAL := 0.0;
    Ts : REAL := 0.0;
    Error : REAL := 0.0;
    P : REAL := 0.0;
    I : REAL := 0.0;
    D : REAL := 0.0;
END_VAR
    Ts := TIME_TO_REAL(CycleTime);
    Error := Setpoint - ProcessValue;

    IF Enable THEN
        P := Kp * Error;
        I := Integral + Ki * Error * Ts;
        Integral := I;

        IF Ts > 0.0 THEN
            D := Kd * (Error - PrevError) / Ts;
        ELSE
            D := 0.0;
        END_IF;

        Output := P + I + D;
        Output := LIMIT(0.0, Output, 100.0);
        PrevError := Error;
    ELSE
        Output := 0.0;
        Integral := 0.0;
        PrevError := 0.0;
    END_IF;
END_FUNCTION_BLOCK

PROGRAM PumpLeadLag
VAR_INPUT
    LevelLow : BOOL;
    LevelHigh : BOOL;
    Pump1Fault : BOOL;
    Pump2Fault : BOOL;
    ManualMode : BOOL;
    ManualP1Run : BOOL;
    ManualP2Run : BOOL;
END_VAR
VAR_OUTPUT
    P1Run : BOOL;
    P2Run : BOOL;
END_VAR
VAR
    LeadPump : INT := 1;
END_VAR

IF ManualMode THEN
    P1Run := ManualP1Run;
    P2Run := ManualP2Run;
ELSE
    (* Переключение ведущего насоса при аварии *)
    IF Pump1Fault AND LeadPump = 1 THEN
        LeadPump := 2;
    ELSIF Pump2Fault AND LeadPump = 2 THEN
        LeadPump := 1;
    END_IF;

    (* Управление по уровню *)
    IF LevelHigh THEN
        P1Run := FALSE;
        P2Run := FALSE;
    ELSIF LevelLow THEN
        IF LeadPump = 1 THEN
            P1Run := TRUE;
            P2Run := FALSE;
        ELSE
            P1Run := FALSE;
            P2Run := TRUE;
        END_IF;
    ELSE
        P1Run := FALSE;
        P2Run := FALSE;
    END_IF;
END_IF;
END_PROGRAM

PROGRAM BatchDoseSequence
VAR_INPUT
    StartSeq : BOOL;
    Abort    : BOOL;
END_VAR
VAR_OUTPUT
    Valve1   : BOOL;
    Valve2   : BOOL;
    Valve3   : BOOL;
    SeqDone  : BOOL;
    SeqActive: BOOL;
END_VAR
VAR
    Step : INT := 0;
    T1   : TON;
    T2   : TON;
    T3   : TON;
END_VAR

IF Abort THEN
    Step       := 0;
    Valve1     := FALSE;
    Valve2     := FALSE;
    Valve3     := FALSE;
    SeqActive  := FALSE;
    SeqDone    := FALSE;
    T1(IN := FALSE, PT := T#2s);
    T2(IN := FALSE, PT := T#3s);
    T3(IN := FALSE, PT := T#1s);
ELSE
    CASE Step OF
        0:
            Valve1     := FALSE;
            Valve2     := FALSE;
            Valve3     := FALSE;
            SeqActive  := FALSE;
            SeqDone    := FALSE;
            IF StartSeq THEN
                Step := 1;
            END_IF;
        1:
            Valve1     := TRUE;
            Valve2     := FALSE;
            Valve3     := FALSE;
            SeqActive  := TRUE;
            SeqDone    := FALSE;
            T1(IN := TRUE, PT := T#2s);
            IF T1.Q THEN
                Step := 2;
            END_IF;
        2:
            Valve1     := FALSE;
            Valve2     := TRUE;
            Valve3     := FALSE;
            SeqActive  := TRUE;
            SeqDone    := FALSE;
            T2(IN := TRUE, PT := T#3s);
            IF T2.Q THEN
                Step := 3;
            END_IF;
        3:
            Valve1     := FALSE;
            Valve2     := FALSE;
            Valve3     := TRUE;
            SeqActive  := TRUE;
            SeqDone    := FALSE;
            T3(IN := TRUE, PT := T#1s);
            IF T3.Q THEN
                Step := 4;
            END_IF;
        4:
            Valve1     := FALSE;
            Valve2     := FALSE;
            Valve3     := FALSE;
            SeqActive  := FALSE;
            SeqDone    := TRUE;
    END_CASE;
END_IF;
END_PROGRAM

PROGRAM SafetyInterlock
VAR_INPUT
    EStopOK : BOOL;
    GuardClosed : BOOL;
    ResetPB : BOOL;
END_VAR
VAR_OUTPUT
    MachineEnable : BOOL;
    SafetyFault : BOOL;
END_VAR
VAR
    ResetTrig : R_TRIG;
END_VAR

ResetTrig(CLK := ResetPB);

IF NOT EStopOK OR NOT GuardClosed THEN
    SafetyFault := TRUE;
ELSIF ResetTrig.Q AND EStopOK AND GuardClosed THEN
    SafetyFault := FALSE;
END_IF;

MachineEnable := NOT SafetyFault AND EStopOK AND GuardClosed;
END_PROGRAM

PROGRAM ProductionCounter
VAR_INPUT
    ProductSensor : BOOL;
    ResetBatch    : BOOL;
    BatchTarget   : INT := 1000;
END_VAR
VAR_OUTPUT
    BatchCount    : INT;
    BatchComplete : BOOL;
    TotalCount    : INT;
END_VAR
VAR
    SensorTrig : R_TRIG;
    Counter    : CTU;
END_VAR

SensorTrig(CLK := ProductSensor);
Counter(CU := SensorTrig.Q, R := ResetBatch, PV := BatchTarget);

BatchCount    := Counter.CV;
BatchComplete := Counter.Q;

IF SensorTrig.Q THEN
    TotalCount := TotalCount + 1;
END_IF;
END_PROGRAM

FUNCTION_BLOCK MovingAverageFilter
VAR_INPUT
    Enable : BOOL;
    RawInput : REAL;
    WindowSize : INT;
END_VAR
VAR_OUTPUT
    Filtered : REAL;
END_VAR
VAR
    Buffer : ARRAY[0..9] OF REAL;
    Head : INT := 0;
    Count : INT := 0;
    Sum : REAL := 0.0;
    EffectiveSize : INT;
END_VAR

IF WindowSize < 1 THEN
    EffectiveSize := 1;
ELSIF WindowSize > 10 THEN
    EffectiveSize := 10;
ELSE
    EffectiveSize := WindowSize;
END_IF;

IF NOT Enable THEN
    Head := 0;
    Count := 0;
    Sum := 0.0;
    Filtered := 0.0;
ELSE
    Buffer[Head] := RawInput;
    IF Count < EffectiveSize THEN
        Count := Count + 1;
        Sum := Sum + RawInput;
    ELSE
        Sum := Sum - Buffer[Head] + RawInput;
    END_IF;

    Head := Head + 1;
    IF Head >= EffectiveSize THEN
        Head := 0;
    END_IF;

    IF Count > 0 THEN
        Filtered := Sum / INT_TO_REAL(Count);
    ELSE
        Filtered := 0.0;
    END_IF;
END_IF;
END_FUNCTION_BLOCK
